.dd-mega { display: grid; grid-template-columns: 1.3fr 1fr; gap: 12px; padding: 12px; min-width: 720px; }
.dd-item { display: flex; align-items: center; gap: 14px; padding: 12px 14px; border-radius: 12px; transition: background 160ms; }
.dd-item:hover { background: #f4f4f5; }
.dd-visual { background: linear-gradient(135deg, #3b82f6, #60a5fa); border-radius: 14px; min-height: 320px; }

var trigger = document.querySelector(".has-dropdown");
trigger.addEventListener("mouseenter", function(){ trigger.classList.add("open"); });
trigger.addEventListener("mouseleave", function(){ trigger.classList.remove("open"); });

.dd-simple { display: flex; flex-direction: column; padding: 8px; min-width: 220px; }
.dd-link { padding: 10px 14px; border-radius: 8px; transition: background 140ms; }
.dd-link:hover { background: #f4f4f5; }

var trigger = document.querySelector(".has-dropdown");
trigger.addEventListener("mouseenter", function(){ trigger.classList.add("open"); });
trigger.addEventListener("mouseleave", function(){ trigger.classList.remove("open"); });

.dd-icons { display: flex; flex-direction: column; gap: 2px; padding: 10px; min-width: 360px; }
.dd-row { display: flex; align-items: center; gap: 14px; padding: 11px 14px; border-radius: 10px; }
.dd-row:hover { background: #f4f4f5; }
.dd-ico { width: 36px; height: 36px; border-radius: 8px; }

.dd-cols { display: grid; grid-template-columns: repeat(4, 1fr); gap: 18px; padding: 18px 22px; min-width: 760px; }
.dd-col h5 { color: #71717a; letter-spacing: 0.1em; text-transform: uppercase; }
.dd-col a { display: block; padding: 6px; border-radius: 6px; }
.dd-col a:hover { background: #f4f4f5; }

.dd-cards { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; padding: 16px; min-width: 720px; }
.dd-card { padding: 14px; border-radius: 12px; background: #f9f9f9; transition: background 160ms, transform 160ms; }
.dd-card:hover { background: #f4f4f5; transform: translateY(-2px); }
.dd-cardimg { width: 100%; height: 88px; border-radius: 8px; margin-bottom: 12px; }

.dd-hp { display: grid; grid-template-columns: 220px 1fr; gap: 8px; min-width: 600px; }
.dd-hp-item:hover, .dd-hp-item.is-on { background: #f4f4f5; }
.dd-hp-preview { position: relative; min-height: 220px; }
.dd-pv { position: absolute; inset: 24px; opacity: 0; transition: opacity 220ms; }
.dd-pv.is-on { opacity: 1; }

document.querySelectorAll(".dd-hp-item").forEach(function(item){
  item.addEventListener("mouseenter", function(){
    var pv = item.dataset.pv;
    document.querySelectorAll(".dd-hp-item").forEach(function(x){ x.classList.toggle("is-on", x.dataset.pv === pv); });
    document.querySelectorAll(".dd-pv").forEach(function(x){ x.classList.toggle("is-on", x.dataset.pv === pv); });
  });
});

.dd-li { opacity: 0; transform: translateY(-6px); transition: opacity 320ms, transform 320ms; }
.has-dropdown.is-open .dd-li { opacity: 1; transform: translateY(0); }
.has-dropdown.is-open .dd-li:nth-child(1) { transition-delay: 0ms; }
.has-dropdown.is-open .dd-li:nth-child(2) { transition-delay: 50ms; }
.has-dropdown.is-open .dd-li:nth-child(3) { transition-delay: 100ms; }

.dd-search-input { display: flex; padding: 8px 12px; background: #f4f4f5; border-radius: 10px; }
.dd-search-input input { flex: 1; border: 0; outline: 0; background: transparent; }
.dd-search-row:hover { background: #f4f4f5; }

.dd-cta-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 18px; padding: 22px 24px; }
.dd-cta-banner { display: flex; justify-content: space-between; padding: 20px 24px; background: linear-gradient(135deg, #171717, #404040); color: #fff; }
.dd-cta-btn { background: #fff; color: #171717; border-radius: 8px; padding: 10px 18px; }
